// worker-public.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/auth')) {
        const authRequest = new Request(request.url, {
          method: request.method,
          headers: request.headers,
          body: request.body,
        });
        return await env.AUTH_SERVICE.fetch(authRequest);
      }

      if (path.startsWith('/api/data')) {
        const dataRequest = new Request(request.url, {
          method: request.method,
          headers: request.headers,
          body: request.body,
        });
        return await env.DATA_SERVICE.fetch(dataRequest);
      }

      if (path.startsWith('/api/process')) {
        const processRequest = new Request(request.url, {
          method: request.method,
          headers: request.headers,
          body: request.body,
        });
        return await env.PROCESSING_SERVICE.fetch(processRequest);
      }

      if (path.startsWith('/api/orchestrate')) {
        const orchestrateRequest = new Request(request.url, {
          method: request.method,
          headers: request.headers,
          body: request.body,
        });
        return await env.ORCHESTRATION_SERVICE.fetch(orchestrateRequest);
      }

      return new Response(JSON.stringify({
        error: 'Not Found',
        message: 'The requested endpoint does not exist'
      }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' }
      });
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

// worker-auth.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/api/auth/login' && request.method === 'POST') {
      const body = await request.json();
      const { username, password } = body;

      const userId = `user_${Math.random().toString(36).substr(2, 9)}`;
      const token = `token_${Math.random().toString(36).substr(2, 16)}`;

      await env.AUTH_KV.put(`token:${token}`, JSON.stringify({
        userId,
        username,
        createdAt: Date.now()
      }), { expirationTtl: 3600 });

      return new Response(JSON.stringify({
        success: true,
        token,
        userId
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/auth/verify' && request.method === 'POST') {
      const body = await request.json();
      const { token } = body;

      const userData = await env.AUTH_KV.get(`token:${token}`);
      
      if (!userData) {
        return new Response(JSON.stringify({
          success: false,
          message: 'Invalid or expired token'
        }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      return new Response(JSON.stringify({
        success: true,
        user: JSON.parse(userData)
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/auth/logout' && request.method === 'POST') {
      const body = await request.json();
      const { token } = body;

      await env.AUTH_KV.delete(`token:${token}`);

      return new Response(JSON.stringify({
        success: true,
        message: 'Logged out successfully'
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({
      error: 'Not Found',
      message: 'Auth endpoint not found'
    }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

// worker-data.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    const authHeader = request.headers.get('Authorization');
    if (authHeader) {
      const token = authHeader.replace('Bearer ', '');
      const verifyRequest = new Request('http://internal/api/auth/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token })
      });
      const verifyResponse = await env.AUTH_SERVICE.fetch(verifyRequest);
      const verifyData = await verifyResponse.json();
      
      if (!verifyData.success) {
        return new Response(JSON.stringify({
          error: 'Unauthorized',
          message: 'Invalid authentication token'
        }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    }

    if (path === '/api/data/create' && request.method === 'POST') {
      const body = await request.json();
      const id = `data_${Math.random().toString(36).substr(2, 9)}`;
      
      await env.DATA_KV.put(id, JSON.stringify({
        ...body,
        id,
        createdAt: Date.now()
      }));

      return new Response(JSON.stringify({
        success: true,
        id,
        data: body
      }), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path.startsWith('/api/data/get/') && request.method === 'GET') {
      const id = path.split('/').pop();
      const data = await env.DATA_KV.get(id);

      if (!data) {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'Data not found'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      return new Response(JSON.stringify({
        success: true,
        data: JSON.parse(data)
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path.startsWith('/api/data/update/') && request.method === 'PUT') {
      const id = path.split('/').pop();
      const body = await request.json();
      
      const existingData = await env.DATA_KV.get(id);
      if (!existingData) {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'Data not found'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const existing = JSON.parse(existingData);
      const updated = {
        ...existing,
        ...body,
        id,
        updatedAt: Date.now()
      };

      await env.DATA_KV.put(id, JSON.stringify(updated));

      return new Response(JSON.stringify({
        success: true,
        data: updated
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path.startsWith('/api/data/delete/') && request.method === 'DELETE') {
      const id = path.split('/').pop();
      await env.DATA_KV.delete(id);

      return new Response(JSON.stringify({
        success: true,
        message: 'Data deleted successfully'
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({
      error: 'Not Found',
      message: 'Data endpoint not found'
    }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

// worker-processing.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/api/process/transform' && request.method === 'POST') {
      const body = await request.json();
      const { dataId, operation } = body;

      const dataRequest = new Request(`http://internal/api/data/get/${dataId}`, {
        method: 'GET',
        headers: request.headers
      });
      const dataResponse = await env.DATA_SERVICE.fetch(dataRequest);
      const dataResult = await dataResponse.json();

      if (!dataResult.success) {
        return new Response(JSON.stringify({
          error: 'Data Not Found',
          message: 'Could not retrieve data for processing'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      let transformedData = dataResult.data;

      switch (operation) {
        case 'uppercase':
          transformedData = Object.fromEntries(
            Object.entries(transformedData).map(([k, v]) => 
              [k, typeof v === 'string' ? v.toUpperCase() : v]
            )
          );
          break;
        case 'lowercase':
          transformedData = Object.fromEntries(
            Object.entries(transformedData).map(([k, v]) => 
              [k, typeof v === 'string' ? v.toLowerCase() : v]
            )
          );
          break;
        case 'reverse':
          transformedData = Object.fromEntries(
            Object.entries(transformedData).map(([k, v]) => 
              [k, typeof v === 'string' ? v.split('').reverse().join('') : v]
            )
          );
          break;
        default:
          break;
      }

      return new Response(JSON.stringify({
        success: true,
        original: dataResult.data,
        transformed: transformedData,
        operation
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/process/analyze' && request.method === 'POST') {
      const body = await request.json();
      const { dataId } = body;

      const dataRequest = new Request(`http://internal/api/data/get/${dataId}`, {
        method: 'GET',
        headers: request.headers
      });
      const dataResponse = await env.DATA_SERVICE.fetch(dataRequest);
      const dataResult = await dataResponse.json();

      if (!dataResult.success) {
        return new Response(JSON.stringify({
          error: 'Data Not Found',
          message: 'Could not retrieve data for analysis'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const data = dataResult.data;
      const analysis = {
        fieldCount: Object.keys(data).length,
        fields: Object.keys(data),
        types: Object.fromEntries(
          Object.entries(data).map(([k, v]) => [k, typeof v])
        ),
        timestamp: Date.now()
      };

      return new Response(JSON.stringify({
        success: true,
        dataId,
        analysis
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/process/batch' && request.method === 'POST') {
      const body = await request.json();
      const { dataIds, operation } = body;

      const results = [];
      
      for (const dataId of dataIds) {
        const processRequest = new Request('http://internal/api/process/transform', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ dataId, operation })
        });
        const processResponse = await env.PROCESSING_SERVICE.fetch(processRequest);
        const result = await processResponse.json();
        results.push({ dataId, result });
      }

      return new Response(JSON.stringify({
        success: true,
        operation,
        processedCount: results.length,
        results
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({
      error: 'Not Found',
      message: 'Processing endpoint not found'
    }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

// worker-orchestration.js
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/api/orchestrate/workflow' && request.method === 'POST') {
      const body = await request.json();
      const { username, password, data, operation } = body;

      const loginRequest = new Request('http://internal/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });
      const loginResponse = await env.AUTH_SERVICE.fetch(loginRequest);
      const loginData = await loginResponse.json();

      if (!loginData.success) {
        return new Response(JSON.stringify({
          error: 'Authentication Failed',
          message: 'Could not authenticate user'
        }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const token = loginData.token;

      const createRequest = new Request('http://internal/api/data/create', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(data)
      });
      const createResponse = await env.DATA_SERVICE.fetch(createRequest);
      const createData = await createResponse.json();

      if (!createData.success) {
        return new Response(JSON.stringify({
          error: 'Data Creation Failed',
          message: 'Could not create data'
        }), {
          status: 500,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const dataId = createData.id;

      const processRequest = new Request('http://internal/api/process/transform', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ dataId, operation })
      });
      const processResponse = await env.PROCESSING_SERVICE.fetch(processRequest);
      const processData = await processResponse.json();

      const updateRequest = new Request(`http://internal/api/data/update/${dataId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          ...processData.transformed,
          processed: true,
          processedOperation: operation
        })
      });
      const updateResponse = await env.DATA_SERVICE.fetch(updateRequest);
      const updateData = await updateResponse.json();

      return new Response(JSON.stringify({
        success: true,
        workflow: 'complete',
        steps: {
          authentication: loginData,
          dataCreation: createData,
          processing: processData,
          dataUpdate: updateData
        }
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (path === '/api/orchestrate/pipeline' && request.method === 'POST') {
      const body = await request.json();
      const { steps } = body;
      
      const results = [];
      let context = {};

      for (const step of steps) {
        const { service, endpoint, method, data } = step;
        
        let serviceBinding;
        switch (service) {
          case 'auth':
            serviceBinding = env.AUTH_SERVICE;
            break;
          case 'data':
            serviceBinding = env.DATA_SERVICE;
            break;
          case 'processing':
            serviceBinding = env.PROCESSING_SERVICE;
            break;
          default:
            continue;
        }

        const requestData = typeof data === 'object' ? 
          JSON.stringify({ ...data, ...context }) : data;

        const stepRequest = new Request(`http://internal${endpoint}`, {
          method: method || 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: requestData
        });

        const stepResponse = await serviceBinding.fetch(stepRequest);
        const stepResult = await stepResponse.json();
        
        results.push({
          service,
          endpoint,
          result: stepResult
        });

        if (stepResult.success) {
          context = { ...context, ...stepResult };
        }
      }

      return new Response(JSON.stringify({
        success: true,
        pipeline: 'complete',
        stepsExecuted: results.length,
        results
      }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({
      error: 'Not Found',
      message: 'Orchestration endpoint not found'
    }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

